                    {achievement.title}
                  </h4>
                  <p className={`text-sm ${isDarkMode ? 'text-white/60' : 'text-slate-600'}`}>
                    {achievement.description}
                  </p>
                </div>
              </div>
            </Card>
          ))}
        </div>
      </div>
    </Layout>
  );
}

