import { createContext, useContext, useState, useEffect, ReactNode } from 'react';

interface ThemeContextType {
  isDarkMode: boolean;
  setIsDarkMode: (value: boolean) => void;
  isBreathing: boolean;
  setIsBreathing: (value: boolean) => void;
  isAudioPlaying: boolean;
  setIsAudioPlaying: (value: boolean) => void;
}

const ThemeContext = createContext<ThemeContextType | undefined>(undefined);

// Store audio element in a way that persists across re-renders
const audioState = {
  element: null as HTMLAudioElement | null,
  initAudio: () => {
    if (!audioState.element) {
      audioState.element = new Audio();
      audioState.element.src = 'https://www.soundhelix.com/examples/mp3/SoundHelix-Song-1.mp3';
      audioState.element.loop = true;
      audioState.element.volume = 0.5;
    }
    return audioState.element;
  }
};

export function ThemeProvider({ children }: { children: ReactNode }) {
  const [isDarkMode, setIsDarkMode] = useState(() => {
    const saved = localStorage.getItem('darkMode');
    return saved ? JSON.parse(saved) : false;
  });
  const [isBreathing, setIsBreathing] = useState(true);
  const [isAudioPlaying, setIsAudioPlaying] = useState(false);

  // Initialize audio element and control playback
  useEffect(() => {
    const audio = audioState.initAudio();

    if (isAudioPlaying) {
      const playPromise = audio.play();
      if (playPromise !== undefined) {
        playPromise.catch(err => {
          console.log('Audio play error:', err);
        });
      }
    } else {
      audio.pause();
      audio.currentTime = 0;
    }
  }, [isAudioPlaying]);

  useEffect(() => {
    localStorage.setItem('darkMode', JSON.stringify(isDarkMode));
    if (isDarkMode) {
      document.documentElement.classList.add('dark');
    } else {
      document.documentElement.classList.remove('dark');
    }
  }, [isDarkMode]);

  return (
    <ThemeContext.Provider value={{ isDarkMode, setIsDarkMode, isBreathing, setIsBreathing, isAudioPlaying, setIsAudioPlaying }}>
      {children}
    </ThemeContext.Provider>
  );
}

export function useTheme() {
  const context = useContext(ThemeContext);
  if (!context) {
    throw new Error('useTheme must be used within a ThemeProvider');
  }
  return context;
}
